12	// AttemptIntegrityPreserveReason is the canonical landing Reason written when
13	// DDx rejects an otherwise-clean attempt because it violated the execute-bead
14	// integrity contract (post-commit mutation, empty pre-commit gate evidence, or
15	// uncommitted changes after the implementation commit). ClassifyExecuteBeadStatus
16	// and classifyLandingFailureMode match on this exact string to route the
17	// attempt to preserved_needs_review + FailureModeAttemptIntegrity rather than
18	// letting it land as success. The specific human explanation lives in the
19	// result's Error field; this constant is the stable machine marker.
20	const AttemptIntegrityPreserveReason = "execute-bead integrity violation"
21	
22	// CommitEvent is one HEAD-moving entry parsed from a worktree's reflog. Action
23	// is the leading verb of the reflog message ("commit", "commit (amend)",
24	// "commit (initial)", "rebase (finish)", "checkout", ...); SHA is the commit
25	// the entry pointed HEAD at.
26	type CommitEvent struct {
27		SHA     string
28		Action  string
29		Subject string
30	}
31	
32	// PreCommitGateRun captures one invocation of a pre-commit gate (e.g.
33	// `lefthook run pre-commit`) and the output it produced, so DDx can tell a
34	// meaningful staged-file gate from a no-op "no staged files" run.
35	type PreCommitGateRun struct {
36		Command string
37		Output  string
38	}
39	
40	// AttemptIntegrityInput is the structured snapshot the post-agent validation
41	// step compares before marking an attempt successful: the commit events the
42	// agent produced, the final implementation revision, the worktree dirty state,
43	// and the pre-commit gate evidence. See ValidateAttemptIntegrity.
44	type AttemptIntegrityInput struct {
45		BaseRev           string
46		ImplementationRev string
47		CommitEvents      []CommitEvent
48		DirtyPaths        []string
49		// CodeChanging is true when the attempt produced an implementation commit,
50		// i.e. the bead changed tracked files and the gate/dirty contracts apply.
51		CodeChanging bool
52		GateRuns     []PreCommitGateRun
53	}
54	
55	// AttemptIntegrityVerdict is the result of ValidateAttemptIntegrity. OK is true
56	// when the attempt satisfies the integrity contract. When OK is false, Reason
57	// is a short machine code and Detail is an operator-facing explanation that
58	// makes clear the rejection came from DDx validation, not from an
59	// implementation/agent failure.
60	type AttemptIntegrityVerdict struct {
61		OK     bool
62		Reason string
63		Detail string
64	}
65	
66	// Integrity reason codes (the Reason field of AttemptIntegrityVerdict).
67	const (
68		IntegrityReasonPostCommitMutation = "post_commit_mutation"
69		IntegrityReasonEmptyGateEvidence  = "empty_gate_evidence"
70		IntegrityReasonDirtyAfterCommit   = "dirty_after_commit"
71	)
72	
73	// reflogLineRe matches a `git reflog show HEAD` line:
74	//
75	//	<sha> HEAD@{N}: <message>
76	var reflogLineRe = regexp.MustCompile(`^(\S+)\s+HEAD@\{\d+\}:\s+(.*)$`)
77	
78	// ParseHeadReflog parses `git reflog show HEAD` output lines (newest-first, as
79	// git emits them) into CommitEvents ordered oldest-first, so callers can reason
80	// about the first commit an agent made versus later rewrites. Lines that do not
81	// match the reflog shape are skipped.
82	func ParseHeadReflog(lines []string) []CommitEvent {
83		var newestFirst []CommitEvent
84		for _, line := range lines {
85			line = strings.TrimRight(line, "\r")
86			m := reflogLineRe.FindStringSubmatch(strings.TrimSpace(line))
87			if m == nil {
88				continue
89			}
90			sha := m[1]
91			message := m[2]
92			action := message
93			subject := ""
94			if idx := strings.Index(message, ": "); idx >= 0 {
95				action = message[:idx]
96				subject = message[idx+2:]
97			}
98			newestFirst = append(newestFirst, CommitEvent{
99				SHA:     sha,
100				Action:  strings.TrimSpace(action),
101				Subject: strings.TrimSpace(subject),
102			})
103		}
104		// Reverse to oldest-first.
105		out := make([]CommitEvent, 0, len(newestFirst))
106		for i := len(newestFirst) - 1; i >= 0; i-- {
107			out = append(out, newestFirst[i])
108		}
109		return out
110	}
