112	// classifyLefthookOutput buckets a single pre-commit gate run's output as
113	// "meaningful" (at least one hook actually executed against staged files),
114	// "no_staged_files" (the run was a no-op because nothing was staged), or
115	// "unknown" (neither signal present). The no_staged_files markers mirror the
116	// phrasing lefthook and the execute-bead prompt use for an empty staged set.
117	func classifyLefthookOutput(output string) string {
118		lower := strings.ToLower(output)
119		noStaged := containsAny(lower,
120			"no files for inspection",
121			"no staged files",
122			"no matching staged files",
123			"no-staged-files",
124			"no files to inspect",
125			"no files matched",
126		)
127		// "executed in" / the success glyphs / "running hook" only appear when a
128		// hook actually ran. Note: "summary: (skip)" is NOT a meaningful marker —
129		// lefthook prints it for no-op runs — so it is deliberately excluded.
130		meaningful := containsAny(lower,
131			"executed in",
132			"✔",
133			"✓",
134			"❯",
135			"running hook",
136		)
137		switch {
138		case meaningful:
139			return "meaningful"
140		case noStaged:
141			return "no_staged_files"
142		default:
143			return "unknown"
144		}
145	}
