147	// ValidateAttemptIntegrity performs the structured post-agent integrity check.
148	// It is pure so it can be exercised directly by regression tests that simulate
149	// an execute-bead transcript. It rejects an attempt when:
150	//
151	//   - the implementation commit was amended or replaced after the first commit
152	//     (post-commit mutation), comparing the first commit event against the final
153	//     implementation revision;
154	//   - the bead changed code but every observed pre-commit gate run reported no
155	//     staged files, so the gate never tested the committed change;
156	//   - the bead changed code but tracked files remained uncommitted after the
157	//     implementation commit.
158	//
159	// Checks that lack evidence (no commit events observed, no gate runs captured)
160	// are skipped rather than failed, so the validator never rejects an attempt it
161	// could not actually observe.
162	func ValidateAttemptIntegrity(in AttemptIntegrityInput) AttemptIntegrityVerdict {
163		if mutated, detail := detectPostCommitMutation(in.CommitEvents, in.ImplementationRev); mutated {
164			return AttemptIntegrityVerdict{
165				Reason: IntegrityReasonPostCommitMutation,
166				Detail: detail,
167			}
168		}
169	
170		if in.CodeChanging && len(in.GateRuns) > 0 {
171			sawMeaningful := false
172			sawNoStaged := false
173			for _, run := range in.GateRuns {
174				switch classifyLefthookOutput(run.Output) {
175				case "meaningful":
176					sawMeaningful = true
177				case "no_staged_files":
178					sawNoStaged = true
179				}
180			}
181			if !sawMeaningful && sawNoStaged {
182				return AttemptIntegrityVerdict{
183					Reason: IntegrityReasonEmptyGateEvidence,
184					Detail: "DDx validation: every pre-commit gate run reported no staged files, so the required pre-commit gate never tested the committed change; this is not acceptance evidence. Detected by DDx, not an implementation failure.",
185				}
186			}
187		}
188	
189		if in.CodeChanging && len(in.DirtyPaths) > 0 {
190			return AttemptIntegrityVerdict{
191				Reason: IntegrityReasonDirtyAfterCommit,
192				Detail: fmt.Sprintf("DDx validation: tracked files remained uncommitted after the implementation commit (%s); the contract requires a clean worktree. Detected by DDx, not an implementation failure.", strings.Join(in.DirtyPaths, ", ")),
193			}
194		}
195	
196		return AttemptIntegrityVerdict{OK: true}
197	}
198	
199	// detectPostCommitMutation reports whether the agent rewrote its implementation
200	// commit after the first commit. It returns true when more than one commit
201	// event is present and either an amend appears after the first commit or the
202	// first commit's SHA differs from the final implementation revision. A single
203	// commit whose SHA matches the implementation revision is clean.
204	func detectPostCommitMutation(events []CommitEvent, implementationRev string) (bool, string) {
205		var commits []CommitEvent
206		for _, ev := range events {
207			if strings.HasPrefix(ev.Action, "commit") {
208				commits = append(commits, ev)
209			}
210		}
211		if len(commits) < 2 {
212			return false, ""
213		}
214		first := commits[0]
215		hasAmend := false
216		for _, c := range commits[1:] {
217			if strings.Contains(c.Action, "amend") {
218				hasAmend = true
219				break
220			}
221		}
222		replaced := implementationRev != "" && first.SHA != "" && !shaEqual(first.SHA, implementationRev)
223		if !hasAmend && !replaced {
224			return false, ""
225		}
226		detail := fmt.Sprintf(
227			"DDx validation: the implementation commit was rewritten after the first commit (%d commit events; first %s, final implementation_rev %s). The execute-bead contract requires exactly one commit with no post-commit amend/rebase. Detected by DDx, not an implementation failure; rerun the bead in a fresh attempt.",
228			len(commits), shortSHA(first.SHA), shortSHA(implementationRev),
229		)
230		return true, detail
231	}
232	
233	// shaEqual reports whether two git revisions refer to the same commit, allowing
234	// for one side being an abbreviation of the other.
235	func shaEqual(a, b string) bool {
236		a = strings.TrimSpace(a)
237		b = strings.TrimSpace(b)
238		if a == "" || b == "" {
239			return false
240		}
241		if a == b {
242			return true
243		}
244		if len(a) < 7 || len(b) < 7 {
245			return false
246		}
247		if len(a) < len(b) {
248			return strings.HasPrefix(b, a)
249		}
250		return strings.HasPrefix(a, b)
251	}
252	
253	func shortSHA(sha string) string {
254		sha = strings.TrimSpace(sha)
255		if len(sha) > 12 {
256			return sha[:12]
257		}
258		if sha == "" {
259			return "(none)"
260		}
261		return sha
262	}
263	
264	// readWorktreeCommitEvents reads the worktree's HEAD reflog and parses it into
265	// oldest-first CommitEvents. Returns nil when the reflog is unavailable (e.g. a
266	// non-git path or a worktree already cleaned up), in which case the post-commit
267	// mutation check is skipped.
268	func readWorktreeCommitEvents(wtPath string) []CommitEvent {
269		if wtPath == "" {
270			return nil
271		}
272		out, err := internalgit.Command(context.Background(), wtPath, "reflog", "show", "HEAD", "--no-abbrev").Output()
273		if err != nil {
274			return nil
275		}
276		return ParseHeadReflog(strings.Split(string(out), "\n"))
277	}
278	
279	// integrityDirtyPaths returns the tracked files that have staged or unstaged
280	// modifications in the worktree (porcelain status with a non-space, non-`?`
281	// status code). Untracked and ignored files are excluded so harness scratch
282	// files and the gitignored evidence dir never trip the dirty check; only real
283	// uncommitted edits to tracked files are reported.
284	func integrityDirtyPaths(wtPath string) []string {
285		if wtPath == "" {
286			return nil
287		}
288		out, err := internalgit.Command(context.Background(), wtPath, "status", "--porcelain").Output()
289		if err != nil {
290			return nil
291		}
292		var paths []string
293		seen := map[string]bool{}
294		for _, line := range strings.Split(string(out), "\n") {
295			line = strings.TrimRight(line, "\r")
296			if len(line) < 4 {
297				continue
298			}
299			code := line[:2]
300			// Skip untracked ("??") entries; only tracked modifications matter.
301			if code == "??" {
302				continue
303			}
304			path := strings.TrimSpace(line[3:])
305			if idx := strings.Index(path, " -> "); idx >= 0 {
306				path = strings.TrimSpace(path[idx+4:])
307			}
308			if path == "" || seen[path] {
309				continue
310			}
311			seen[path] = true
312			paths = append(paths, path)
313		}
314		return paths
315	}
